module adder_pipe_64bit(
    input clk,
    input rst_n,
    input [63:0] i_a,
    input [63:0] i_b,
    input i_en,
    output [63:0] o_result,
    output o_en
);

reg [63:0] a_reg, b_reg;
reg [1:0] en_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        a_reg <= 64'b0;
        b_reg <= 64'b0;
        en_reg <= 2'b0;
    end else begin
        a_reg <= i_a;
        b_reg <= i_b;
        en_reg <= {en_reg[0], i_en};
    end
end

wire [63:0] sum;
wire cout;

// 64-bit ripple carry adder
genvar i;
generate
    for (i = 0; i < 64; i = i + 1) begin
        if (i == 0) begin
            assign {cout, sum[0]} = a_reg[0] + b_reg[0] + 1'b0;
        end else begin
            assign {cout, sum[i]} = a_reg[i] + b_reg[i] + cout;
        end
    end
endgenerate

reg [63:0] result_reg;
reg result_en;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        result_reg <= 64'b0;
        result_en <= 1'b0;
    end else begin
        result_reg <= sum;
        result_en <= en_reg[1];
    end
end

assign o_result = result_reg;
assign o_en = result_en;

endmodule
